export function PostCard({
  title,
  bodyPreview,
  authorName,
  authorAvatar,
  authorBadge,
  bannerImage,
  postType,
  readingTime,
  likeCount,
  commentCount,
  bookmarkCount,
  isLiked,
  isBookmarked,
  userReaction,
  onPress,
  onLike,
  onComment,
  onBookmark,
  onRepost,
  onReact,
  onAuthorPress,
  isRepost,
  repostCaption,
  repostSourceTitle,
  repostSourcePreview,
  repostSourceAuthorName,
  repostSourceAuthorAvatar,
  onEmbeddedPress,
}: PostCardProps) {
  const {colors} = useTheme();
