                style={[
                  styles.embeddedCard,
                  {borderColor: colors.borderCard, backgroundColor: colors.bgPrimary},
                ]}>
                <View style={styles.embeddedAuthorRow}>
                  <Avatar
                    uri={repostSourceAuthorAvatar}
